{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラの正式キックオフおよび発足を承認し、実効業務として開始する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "毎週水曜日 10:00〜に週次定例ミーティングを開催し、各部署より少なくとも1名の参加を必須とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "本番リリースの目標時期を「2026年10月15日」に変更する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "開発ベンダー候補のうち、「コマツバ・ソリューションズ」を仮予約/候補として残す。",
      "decided_by": "郡司 明久、桐生 遥"
    },
    {
      "id": "D5",
      "content": "共通基盤（認証・マスタ配信）について、サクラ商事が提供する認証基盤の共同利用で進めることを確定する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "移行方式として「B案：段階移行」を採用することを確定する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "データ移行方針として、第1フェーズではマスターデータのみを移行し、トランザクションデータは旧システムで参照用として残すことを確定する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D8",
      "content": "ユーザー権限について、新規でのロール再設計は行わず、既存のロール定義を流用することを確定する。",
      "decided_by": "芦田 巧、桐生 遥"
    },
    {
      "id": "D9",
      "content": "新システム導入後の一次障害受付窓口を、情報システム部からQAチームに変更することを確定する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D10",
      "content": "各拠点グループへの切り替え作業を、土曜日の深夜帯〜日曜日早朝に行うことを確定する。",
      "decided_by": "会議全体"
    }
  ],
  "action_items": [
    {
      "id": "A1",
      "task": "外部連携インターフェースのエンドポイント一覧、主要項目レイアウトを含むAPI仕様書のドラフトを作成する。",
      "assignee": "芦田 巧",
      "due": "2026-05-20"
    },
    {
      "id": "A2",
      "task": "構成を見直し後の検証環境のサーバ調達依頼書を提出する。",
      "assignee": "沼田 賢一",
      "due": "2026-05-15"
    },
    {
      "id": "A3",
      "task": "在庫管理に関わる部署名および窓口候補者氏名を含む、現場ヒアリングの対象部署リストを提出する。",
      "assignee": "東雲 美咲",
      "due": "2026-05-19"
    },
    {
      "id": "A4",
      "task": "コマツバ・ソリューションズ社との契約に向けたベンダー見積の社内稟議を起票する。",
      "assignee": "郡司 明久",
      "due": "2026-05-18"
    },
    {
      "id": "A5",
      "task": "開発用ライセンスの単価確認および年契約条件を含め、外部ライセンス費用を再見積もりする。",
      "assignee": "郡司 明久",
      "due": "2026-06-01"
    },
    {
      "id": "A6",
      "task": "現行システムのテストケースを生きている・捨てる・要修正の3分類に整理し一覧表を作成する。",
      "assignee": "白鳥 千夏",
      "due": "2026-05-29"
    },
    {
      "id": "A7",
      "task": "切り戻し手順含む検証項目を入れる、移行テスト計画書を作成する。",
      "assignee": "芦田 巧",
      "due": "2026-06-03"
    },
    {
      "id": "A8",
      "task": "ピーク想定シナリオに基づく負荷テスト計画書を作成する。",
      "assignee": "白鳥 千夏",
      "due": "2026-06-03"
    },
    {
      "id": "A9",
      "task": "骨組みを作成し、白鳥がレビューする形とする移行リハーサル手順書を作成する。",
      "assignee": "沼田 賢一",
      "due": "2026-06-05"
    },
    {
      "id": "A10",
      "task": "サクラ商事への共同利用回答書を作成し送付する。",
      "assignee": "桐生 遥",
      "due": "2026-05-19"
    },
    {
      "id": "A11",
      "task": "各拠点の生産管理担当に対し説明会の日程案を打診し、5月下旬〜6月頭のスケジュールを確定させる。",
      "assignee": "東雲 美咲",
      "due": "2026-05-27"
    },
    {
      "id": "A13",
      "task": "検証環境とは別に、負荷試験専用の縮小構成但し本番相当環境を準備する。",
      "assignee": "沼田 賢一",
      "due": "2026-05-25"
    },
    {
      "id": "A14",
      "task": "議事録を作成し共有する。",
      "assignee": "桐生 遥",
      "due": "2026-05-13"
    }
  ],
